import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom'; // Correct imports
import './App.css';
import LoginPage from './Components/Login';
import SignupPage from './Components/Signup';
import SideNav from './Components/SideNav'; // Import the SideNav component
import ChatBox from './Components/ChatBox';
import HomePage from './Components/HomePage'; // Import the HomePage component
import Settings from './Components/Settings'; // Assume you have a Settings component
import ImportDataSidebar from './Components/ImportDataSidebar'; // Import the ImportDataSidebar component

function AppContent() {
  const [isAuthenticated, setIsAuthenticated] = useState(false); // Manage login state

  // States for settings data and sidebar visibility
  const [domain, setDomain] = useState('');
  const [project, setProject] = useState('');
  const [issueType, setIssueType] = useState('');
  const [jiraData, setJiraData] = useState([]);
  const [isSidebarVisible, setIsSidebarVisible] = useState(false);

  // Handle login success
  const login = () => {
    setIsAuthenticated(true);
  };

  // Handle logout (navigate to login page)
  const logout = () => {
    setIsAuthenticated(false);
  };

  // Fetch Jira data based on settings
  const handleFetchData = async (domain, project, issueType) => {
    try {
      const response = await fetch(
        `https://localhost:7216/api/UserStoryDescription/ExportAllUserStories?domain=${domain}&project=${project}&issueType=${issueType}`,
        {
          method: 'GET',
        }
      );
      if (response.ok) {
        const data = await response.json();
        setJiraData(data);  // Set the fetched Jira data
        setIsSidebarVisible(true);  // Show the sidebar with data
      } else {
        alert('Error fetching data');
      }
    } catch (error) {
      console.error('Error fetching data:', error);
    }
  };

  return (
    <div className="App">
      <h1>J-Test</h1>

      {/* Render SideNav only if authenticated */}
      {isAuthenticated && <SideNav logout={logout} />} {/* Pass logout to SideNav */}

      <Routes>
        {/* Login Route */}
        <Route path="/Login" element={<LoginPage login={login} />} />

        {/* Signup Route */}
        <Route path="/Signup" element={<SignupPage />} />

        {/* HomePage Route - Ensure it's accessible when authenticated */}
        <Route
          path="/HomePage"
          element={isAuthenticated ? <HomePage /> : <Navigate to="/Login" />}
        />

        {/* ChatBox Route - Allow access regardless of authentication */}
        <Route path="/ChatBox" element={<ChatBox />} />

        {/* Settings Route - Allow access when authenticated */}
        <Route
          path="/Settings"
          element={
            isAuthenticated ? (
              <Settings
                domain={domain}
                setDomain={setDomain}
                project={project}
                setProject={setProject}
                issueType={issueType}
                setIssueType={setIssueType}
                onSubmit={handleFetchData}
              />
            ) : (
              <Navigate to="/Login" />
            )
          }
        />

        {/* Default route - Redirect to Login if no route matches */}
        <Route path="/" element={<Navigate to="/Login" />} />
      </Routes>

      {/* Import Data Sidebar - Show when Jira data is fetched */}
      <ImportDataSidebar
        jiraData={jiraData}
        isSidebarVisible={isSidebarVisible}
        onClose={() => setIsSidebarVisible(false)}
      />
    </div>
  );
}

// App component should only include the Router wrapper
function App() {
  return (
    <Router>
      <AppContent /> {/* Wrap the logic of App inside AppContent component */}
    </Router>
  );
}

export default App;
